349 static bool processCmp(CmpInst *Cmp, LazyValueInfo *LVI) {
350   if (constantFoldCmp(Cmp, LVI))
351     return true;
352 
353   if (auto *ICmp = dyn_cast<ICmpInst>(Cmp))
354     if (processICmp(ICmp, LVI))
355       return true;
356 
357   return false;
358 }
